// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// RESOURCE PLANNING · AllocationChart
// Multi-series area chart showing planned vs actual vs reserved
// compute. Allocated is the white baseline, used is the live accent
// signal, reserved is a faint peripheral series.
// ============================================================

'use client';

import { useState } from 'react';
import {
  AreaChart, Area, BarChart, Bar,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
} from 'recharts';
import { ChartLine, ChartBar } from '@phosphor-icons/react';
import { tokens } from '../../tokens';
import { CornerMarkers } from '../../components/CornerMarkers';
import { Toggle } from '../../components/Toggle';
import { SegmentedControl } from '../../components/SegmentedControl';
import { allocationSeries } from './data';

function InsetDivider({ side = 'bottom' }) {
  return (
    <span
      aria-hidden
      style={{
        position: 'absolute',
        left: tokens.spacing[3],
        right: tokens.spacing[3],
        [side]: 0,
        height: '1px',
        background: tokens.color.border.subtle,
        pointerEvents: 'none',
      }}
    />
  );
}

const SERIES = [
  { key: 'allocated', label: 'Allocated', color: tokens.color.text.secondary  },
  { key: 'used',      label: 'Used',      color: tokens.color.accent[400]   },
  { key: 'reserved',  label: 'Reserved',  color: tokens.color.text.faint    },
];

// ── Custom tooltip ───────────────────────────────────────────────
function ChartTooltip({ active, payload, label }) {
  if (!active || !payload?.length) return null;
  const ordered = ['allocated', 'used', 'reserved'].map((k) => payload.find((p) => p.dataKey === k)).filter(Boolean);
  return (
    <div
      style={{
        position: 'relative',
        background: tokens.color.surface.overlay,
        border: `${tokens.border.thin} ${tokens.color.border.bright}`,
        padding: `${tokens.spacing[3]} ${tokens.spacing[4]}`,
        fontFamily: tokens.typography.fontMono,
        minWidth: '180px',
      }}
    >
      <div
        style={{
          fontSize: tokens.typography.size.xs,
          color: tokens.color.text.muted,
          textTransform: 'uppercase',
          letterSpacing: tokens.typography.tracking.widest,
          marginBottom: tokens.spacing[2],
        }}
      >
        AUG {String(label).padStart(2, '0')}
      </div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: tokens.spacing[1] }}>
        {ordered.map((p) => {
          const meta = SERIES.find((s) => s.key === p.dataKey);
          return (
            <div key={p.dataKey} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'baseline', gap: tokens.spacing[4] }}>
              <span
                style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: tokens.spacing[2],
                  fontSize: tokens.typography.size.sm,
                  color: tokens.color.text.muted,
                  letterSpacing: tokens.typography.tracking.wide,
                }}
              >
                <span aria-hidden style={{ width: '6px', height: '6px', background: meta.color, flexShrink: 0 }} />
                {meta.label}
              </span>
              <span
                style={{
                  fontSize: tokens.typography.size.sm,
                  color: tokens.color.text.primary,
                  fontWeight: tokens.typography.weight.medium,
                  letterSpacing: tokens.typography.tracking.wide,
                }}
              >
                {p.value.toLocaleString('en-US')}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── Legend chip ──────────────────────────────────────────────────
function LegendChip({ color, label, active, onClick }) {
  return (
    <button
      type="button"
      onClick={onClick}
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        gap: tokens.spacing[2],
        padding: `${tokens.spacing[1]} ${tokens.spacing[2]}`,
        background: 'transparent',
        border: 'none',
        cursor: 'pointer',
        opacity: active ? 1 : 0.4,
        fontFamily: tokens.typography.fontMono,
        fontSize: tokens.typography.size.sm,
        color: tokens.color.text.secondary,
        letterSpacing: tokens.typography.tracking.wide,
      }}
    >
      <span aria-hidden style={{ width: '10px', height: '10px', background: color, flexShrink: 0 }} />
      {label}
    </button>
  );
}

// ── Composition ──────────────────────────────────────────────────
export function AllocationChart() {
  const [mode, setMode] = useState('line');
  const [visible, setVisible] = useState({ allocated: true, used: true, reserved: true });
  const [vsPrev, setVsPrev] = useState(false);

  function toggle(key) {
    setVisible((v) => ({ ...v, [key]: !v[key] }));
  }

  return (
    <div
      style={{
        position: 'relative',
        background: tokens.color.surface.raised,
        display: 'flex',
        flexDirection: 'column',
        flex: 1,
        minHeight: 0,
      }}
    >
      <CornerMarkers />

      {/* Header */}
      <div
        style={{
          position: 'relative',
          display: 'flex',
          alignItems: 'center',
          gap: tokens.spacing[3],
          padding: `${tokens.spacing[4]} ${tokens.spacing[5]}`,
        }}
      >
        <InsetDivider />
        <span
          style={{
            fontFamily: tokens.typography.fontSans,
            fontSize: tokens.typography.size.xl,
            fontWeight: tokens.typography.weight.semibold,
            color: tokens.color.text.primary,
            letterSpacing: tokens.typography.tracking.tight,
          }}
        >
          Allocation vs usage
        </span>
        <div style={{ flex: 1 }} />
        <SegmentedControl
          size="md"
          value={mode}
          onChange={setMode}
          options={[
            { value: 'line', icon: ChartLine, ariaLabel: 'Line chart' },
            { value: 'bar',  icon: ChartBar,  ariaLabel: 'Bar chart'  },
          ]}
        />
      </div>

      {/* Chart */}
      <div style={{ position: 'relative', flex: 1, minHeight: 0, padding: `${tokens.spacing[4]} ${tokens.spacing[5]} 0 ${tokens.spacing[5]}` }}>
        {/* Y-axis label (top-left) */}
        <span
          style={{
            position: 'absolute',
            top: tokens.spacing[2],
            left: tokens.spacing[5],
            fontFamily: tokens.typography.fontMono,
            fontSize: tokens.typography.size.xs,
            color: tokens.color.text.muted,
            textTransform: 'uppercase',
            letterSpacing: tokens.typography.tracking.widest,
          }}
        >
          Compute units, PFLOPS
        </span>

        <ResponsiveContainer width="100%" height="100%">
          {mode === 'line' ? (
            <AreaChart data={allocationSeries} margin={{ top: 32, right: 8, left: 0, bottom: 12 }}>
              <defs>
                {SERIES.map((s) => (
                  <linearGradient key={s.key} id={`rp-fill-${s.key}`} x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%"   stopColor={s.color} stopOpacity={0.12} />
                    <stop offset="100%" stopColor={s.color} stopOpacity={0}    />
                  </linearGradient>
                ))}
              </defs>
              <CartesianGrid strokeDasharray="2 4" stroke={tokens.color.border.subtle} vertical={false} />
              <XAxis
                dataKey="t"
                tick={{
                  fontFamily: tokens.typography.fontMono,
                  fontSize: parseInt(tokens.typography.size.xs, 10),
                  fill: tokens.color.text.muted,
                  letterSpacing: '0.05em',
                }}
                axisLine={{ stroke: tokens.color.border.subtle }}
                tickLine={false}
                interval={4}
              />
              <YAxis
                tick={{
                  fontFamily: tokens.typography.fontMono,
                  fontSize: parseInt(tokens.typography.size.xs, 10),
                  fill: tokens.color.text.muted,
                  letterSpacing: '0.05em',
                }}
                axisLine={false}
                tickLine={false}
                width={48}
              />
              <Tooltip
                content={<ChartTooltip />}
                cursor={{ stroke: tokens.color.border.bright, strokeWidth: 1, strokeDasharray: '2 4' }}
              />
              {SERIES.map((s) => visible[s.key] ? (
                <Area
                  key={s.key}
                  type="monotone"
                  dataKey={s.key}
                  stroke={s.color}
                  strokeWidth={1.5}
                  fill={`url(#rp-fill-${s.key})`}
                  dot={false}
                  activeDot={{ r: 4, fill: s.color, stroke: tokens.color.surface.raised, strokeWidth: 1 }}
                />
              ) : null)}
            </AreaChart>
          ) : (
            <BarChart data={allocationSeries} margin={{ top: 32, right: 8, left: 0, bottom: 12 }}>
              <CartesianGrid strokeDasharray="2 4" stroke={tokens.color.border.subtle} vertical={false} />
              <XAxis
                dataKey="t"
                tick={{
                  fontFamily: tokens.typography.fontMono,
                  fontSize: parseInt(tokens.typography.size.xs, 10),
                  fill: tokens.color.text.muted,
                  letterSpacing: '0.05em',
                }}
                axisLine={{ stroke: tokens.color.border.subtle }}
                tickLine={false}
                interval={4}
              />
              <YAxis
                tick={{
                  fontFamily: tokens.typography.fontMono,
                  fontSize: parseInt(tokens.typography.size.xs, 10),
                  fill: tokens.color.text.muted,
                  letterSpacing: '0.05em',
                }}
                axisLine={false}
                tickLine={false}
                width={48}
              />
              <Tooltip
                content={<ChartTooltip />}
                cursor={{ fill: tokens.color.surface.hover }}
              />
              {SERIES.map((s) => visible[s.key] ? (
                <Bar key={s.key} dataKey={s.key} fill={s.color} />
              ) : null)}
            </BarChart>
          )}
        </ResponsiveContainer>
      </div>

      {/* Footer — series toggles + vs previous period */}
      <div
        style={{
          position: 'relative',
          display: 'flex',
          alignItems: 'center',
          gap: tokens.spacing[3],
          padding: `${tokens.spacing[3]} ${tokens.spacing[5]}`,
        }}
      >
        <InsetDivider side="top" />
        {SERIES.map((s) => (
          <LegendChip
            key={s.key}
            color={s.color}
            label={s.label}
            active={visible[s.key]}
            onClick={() => toggle(s.key)}
          />
        ))}
        <div style={{ flex: 1 }} />
        <span
          style={{
            display: 'inline-flex',
            alignItems: 'center',
            gap: tokens.spacing[2],
            fontFamily: tokens.typography.fontMono,
            fontSize: tokens.typography.size.sm,
            color: tokens.color.text.muted,
            letterSpacing: tokens.typography.tracking.wide,
          }}
        >
          <Toggle checked={vsPrev} onCheckedChange={setVsPrev} />
          Vs. previous period
        </span>
      </div>
    </div>
  );
}

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// RESOURCE PLANNING · CapacityPanel
// Top-left card. Three KPI cells separated by 1px borders, each with
// a different micro-visual: skewed bar grid, gradient threshold bar,
// and a sparkline.
// ============================================================

'use client';

import { AreaChart, Area, YAxis, ResponsiveContainer } from 'recharts';
import { tokens } from '../../tokens';
import { CornerMarkers } from '../../components/CornerMarkers';
import { PanelHeader } from '../../components/PanelHeader';
import { PanelMenu } from '../../components/PanelMenu';
import { ArrowClockwise, Sliders, Export, EyeSlash } from '@phosphor-icons/react';
import { clusterUtilisation, missionSuccessRate, activeAllocations } from './data';

// ── Reusable cell wrapper ─────────────────────────────────────────
function Cell({ label, children, last = false }) {
  return (
    <div
      style={{
        flex: '1 1 0',
        minWidth: 0,
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'space-between',
        gap: tokens.spacing[3],
        padding: `${tokens.spacing[5]} ${tokens.spacing[5]}`,
        borderRight: last ? 'none' : `${tokens.border.thin} ${tokens.color.border.subtle}`,
      }}
    >
      <span
        style={{
          fontFamily: tokens.typography.fontMono,
          fontSize: tokens.typography.size.xs,
          color: tokens.color.text.muted,
          textTransform: 'uppercase',
          letterSpacing: tokens.typography.tracking.widest,
        }}
      >
        {label}
      </span>
      {children}
    </div>
  );
}

// ── Headline number ───────────────────────────────────────────────
function BigValue({ value, suffix, delta }) {
  return (
    <div style={{ display: 'flex', alignItems: 'baseline', gap: tokens.spacing[2] }}>
      <span
        style={{
          fontFamily: tokens.typography.fontMono,
          fontSize: tokens.typography.size['3xl'],
          fontWeight: tokens.typography.weight.bold,
          color: tokens.color.text.primary,
          letterSpacing: tokens.typography.tracking.tight,
          lineHeight: tokens.typography.lineHeight.tight,
        }}
      >
        {value}
      </span>
      {suffix ? (
        <span
          style={{
            fontFamily: tokens.typography.fontMono,
            fontSize: tokens.typography.size.md,
            color: tokens.color.text.muted,
            letterSpacing: tokens.typography.tracking.wide,
          }}
        >
          {suffix}
        </span>
      ) : null}
      {typeof delta === 'number' ? (
        <span
          style={{
            display: 'inline-flex',
            alignItems: 'baseline',
            gap: tokens.spacing[1],
            fontFamily: tokens.typography.fontMono,
            fontSize: tokens.typography.size.sm,
            color: tokens.color.accent[300],
            letterSpacing: tokens.typography.tracking.wide,
          }}
        >
          ▲ {delta.toFixed(1)}%
        </span>
      ) : null}
    </div>
  );
}

// ── Shared visualisation slot ─────────────────────────────────────
// Every viz in the CapacityPanel renders into a 40px-tall slot, anchored
// to the bottom of its cell, so the three cells line up perfectly across
// the row regardless of which visual they contain.
const VIZ_HEIGHT = 40;

// ── Skewed-bar grid (cluster utilisation) ────────────────────────
function BarGrid({ values }) {
  return (
    <div style={{ display: 'flex', gap: '3px', alignItems: 'flex-end', height: `${VIZ_HEIGHT}px`, width: '100%' }}>
      {values.map((v, i) => (
        <div
          key={i}
          style={{
            flex: '1 1 0',
            minWidth: 0,
            height: `${Math.max(8, v * VIZ_HEIGHT)}px`,
            transform: 'skewX(-12deg)',
            background: tokens.color.accent[400],
          }}
        />
      ))}
    </div>
  );
}

// ── Gradient threshold bar (mission success) ─────────────────────
// Renders into the same 40px slot as the other viz. The bar pins to the
// top of the slot (so the marker sits comfortably above it) and the
// 0% / 100% labels pin to the bottom.
function ThresholdBar({ value }) {
  return (
    <div
      style={{
        position: 'relative',
        height: `${VIZ_HEIGHT}px`,
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'space-between',
      }}
    >
      <div
        style={{
          position: 'relative',
          marginTop: '8px',
          height: '12px',
          background: `linear-gradient(90deg, ${tokens.color.red[400]} 0%, ${tokens.color.orange[300]} 50%, ${tokens.color.accent[300]} 100%)`,
          border: `${tokens.border.thin} ${tokens.color.border.subtle}`,
        }}
      >
        {/* Marker — anchored above the bar with a downward arrow */}
        <span
          aria-hidden
          style={{
            position: 'absolute',
            top: '-8px',
            left: `calc(${value}% - 4px)`,
            width: 0,
            height: 0,
            borderLeft: `4px solid transparent`,
            borderRight: `4px solid transparent`,
            borderTop: `6px solid ${tokens.color.text.primary}`,
          }}
        />
      </div>
      <div style={{ display: 'flex', justifyContent: 'space-between' }}>
        <span style={{ fontFamily: tokens.typography.fontMono, fontSize: tokens.typography.size.xs, color: tokens.color.text.faint, letterSpacing: tokens.typography.tracking.wider }}>
          0%
        </span>
        <span style={{ fontFamily: tokens.typography.fontMono, fontSize: tokens.typography.size.xs, color: tokens.color.text.faint, letterSpacing: tokens.typography.tracking.wider }}>
          100%
        </span>
      </div>
    </div>
  );
}

// ── Sparkline (active allocations) ───────────────────────────────
function Sparkline({ data }) {
  return (
    <div style={{ height: `${VIZ_HEIGHT}px`, width: '100%' }}>
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={data} margin={{ top: 4, right: 0, left: 0, bottom: 2 }}>
          <defs>
            <linearGradient id="rp-spark-fill" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%"   stopColor={tokens.color.text.primary} stopOpacity={0.12} />
              <stop offset="100%" stopColor={tokens.color.text.primary} stopOpacity={0}    />
            </linearGradient>
          </defs>
          {/* Hidden axis — clamps the Y range to the actual data so the
              rise reads visually instead of being flattened by the default
              [0, dataMax] domain. */}
          <YAxis hide domain={['dataMin', 'dataMax']} />
          <Area
            type="monotone"
            dataKey="v"
            stroke={tokens.color.text.primary}
            strokeWidth={1.25}
            fill="url(#rp-spark-fill)"
            dot={false}
            isAnimationActive={false}
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
}

// ── Composition ──────────────────────────────────────────────────
export function CapacityPanel() {
  return (
    <div
      style={{
        position: 'relative',
        background: tokens.color.surface.raised,
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      <CornerMarkers />

      <PanelHeader
        title="Capacity"
        actions={
          <PanelMenu
            ariaLabel="Capacity options"
            items={[
              { label: 'Refresh',   icon: ArrowClockwise, onSelect: () => {} },
              { label: 'Configure', icon: Sliders,        onSelect: () => {} },
              { label: 'Export',    icon: Export,         onSelect: () => {} },
              { type: 'separator' },
              { label: 'Hide',      icon: EyeSlash,       onSelect: () => {} },
            ]}
          />
        }
      />

      {/* Three KPI cells — flex:1 so the row fills the panel height in
          a bento grid where both top panels share a single row height. */}
      <div style={{ display: 'flex', flex: 1, minHeight: 0 }}>
        <Cell label="Cluster utilisation">
          <BigValue value={`${clusterUtilisation.value.toFixed(1)}`} suffix="%" />
          <BarGrid values={clusterUtilisation.segments} />
        </Cell>
        <Cell label="Mission success rate">
          <BigValue value={`${missionSuccessRate.value.toFixed(1)}`} suffix="%" />
          <ThresholdBar value={missionSuccessRate.value} />
        </Cell>
        <Cell label="Active allocations" last>
          <BigValue value={activeAllocations.value.toLocaleString('en-US')} delta={activeAllocations.delta} />
          <Sparkline data={activeAllocations.series} />
        </Cell>
      </div>
    </div>
  );
}

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// RESOURCE PLANNING · RequestsPanel
// Top-right card. Three breakdown cells (approved / pending /
// rejected) and a stacked-share bar at the bottom that reads as a
// single horizontal split rather than three independent bars.
// ============================================================

'use client';

import { tokens } from '../../tokens';
import { CornerMarkers } from '../../components/CornerMarkers';
import { PanelHeader } from '../../components/PanelHeader';
import { PanelMenu } from '../../components/PanelMenu';
import { ArrowClockwise, Export, Check, EyeSlash } from '@phosphor-icons/react';
import { requestsBreakdown } from './data';

const BUCKETS = [
  { key: 'approved', label: 'Approved', color: tokens.color.accent[400], borderColor: tokens.color.accent[200] },
  { key: 'pending',  label: 'Pending',  color: tokens.color.orange[400], borderColor: tokens.color.orange[200] },
  { key: 'rejected', label: 'Rejected', color: tokens.color.red[400],    borderColor: tokens.color.red[200]    },
];

// ── Single breakdown cell ─────────────────────────────────────────
function Cell({ label, value, share, last = false }) {
  return (
    <div
      style={{
        flex: '1 1 0',
        minWidth: 0,
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'space-between',
        gap: tokens.spacing[2],
        padding: `${tokens.spacing[5]} ${tokens.spacing[5]}`,
        borderRight: last ? 'none' : `${tokens.border.thin} ${tokens.color.border.subtle}`,
      }}
    >
      <span
        style={{
          fontFamily: tokens.typography.fontMono,
          fontSize: tokens.typography.size.xs,
          color: tokens.color.text.muted,
          textTransform: 'uppercase',
          letterSpacing: tokens.typography.tracking.widest,
        }}
      >
        {label}
      </span>
      <span
        style={{
          fontFamily: tokens.typography.fontMono,
          fontSize: tokens.typography.size['2xl'],
          fontWeight: tokens.typography.weight.bold,
          color: tokens.color.text.primary,
          letterSpacing: tokens.typography.tracking.tight,
          lineHeight: tokens.typography.lineHeight.tight,
        }}
      >
        {value}
      </span>
      <span
        style={{
          fontFamily: tokens.typography.fontMono,
          fontSize: tokens.typography.size.sm,
          color: tokens.color.text.muted,
          letterSpacing: tokens.typography.tracking.wide,
        }}
      >
        {(share * 100).toFixed(1)}%
      </span>
    </div>
  );
}

// ── Stacked-share bar ─────────────────────────────────────────────
// Single horizontal bar with three skewed parallelogram segments,
// matching the ProgressBar diagonal motif. Each segment width
// reflects its share of the total.
function StackedBar() {
  return (
    <div
      style={{
        display: 'flex',
        gap: '3px',
        height: tokens.spacing[5],
        padding: `0 ${tokens.spacing[5]} ${tokens.spacing[5]} ${tokens.spacing[5]}`,
      }}
    >
      {BUCKETS.map((b) => {
        const share = requestsBreakdown[b.key].share;
        return (
          <div
            key={b.key}
            style={{
              flex: `${share} 1 0`,
              minWidth: 0,
              height: '100%',
              transform: 'skewX(-12deg)',
              background: b.color,
              border: `1px solid ${b.borderColor}`,
            }}
          />
        );
      })}
    </div>
  );
}

// ── Composition ──────────────────────────────────────────────────
export function RequestsPanel() {
  return (
    <div
      style={{
        position: 'relative',
        background: tokens.color.surface.raised,
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      <CornerMarkers />

      <PanelHeader
        title="Requests"
        actions={
          <PanelMenu
            ariaLabel="Requests options"
            items={[
              { label: 'Refresh', icon: ArrowClockwise, onSelect: () => {} },
              { label: 'Review',  icon: Check,          onSelect: () => {} },
              { label: 'Export',  icon: Export,         onSelect: () => {} },
              { type: 'separator' },
              { label: 'Hide',    icon: EyeSlash,       onSelect: () => {} },
            ]}
          />
        }
      />

      {/* Three cells — flex:1 so the row fills the panel height. */}
      <div style={{ display: 'flex', flex: 1, minHeight: 0 }}>
        {BUCKETS.map((b, i) => (
          <Cell
            key={b.key}
            label={b.label}
            value={requestsBreakdown[b.key].value}
            share={requestsBreakdown[b.key].share}
            last={i === BUCKETS.length - 1}
          />
        ))}
      </div>

      {/* Stacked share bar */}
      <StackedBar />
    </div>
  );
}

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// RESOURCE PLANNING · RequestsTable
// Filter tabs, search field, and the request log itself. Rows
// are neutral — selection is the only row-level state, conveyed
// by the leading checkbox; the active filter tab carries the
// "kind of request" context above the table.
// ============================================================

'use client';

import { useState } from 'react';
import { motion, AnimatePresence, LayoutGroup } from 'framer-motion';
import { MagnifyingGlass, CaretUp } from '@phosphor-icons/react';
import { tokens } from '../../tokens';
import { CornerMarkers } from '../../components/CornerMarkers';
